int solveQuery(int start, int end, vector<int>& arr) {
    unordered_map<int, int> frequency;
    // Calculate the frequency of each element in the range
    for (int i = start; i <= end; ++i) {
        if (frequency.find(arr[i]) != frequency.end()) {
            frequency[arr[i]] += 1;
        } else {
            frequency[arr[i]] = 1;
        }
    }
    int count = 0;
    // Check if element equals its frequency
    for (const auto& pair : frequency) {
        if (pair.first == pair.second) {
            count += 1;
        }
    }
    return count;
}

