bool check(const std::string& s1, const std::string& s2) {
    int n = s1.length();
    int m = s2.length();
    // Initialize a 2D dp vector
    std::vector<std::vector<bool>> dp(n + 1, std::vector<bool>(m + 1, false));
    dp[0][0] = true;
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j <= m; ++j) {
            if (dp[i][j]) {
                // If current character in s1 (upper case) matches with s2
                if (j < m && std::toupper(s1[i]) == s2[j]) {
                    dp[i + 1][j + 1] = true;
                }
                // If current character in s1 is not upper case, it can be skipped
                if (!std::isupper(s1[i])) {
                    dp[i + 1][j] = true;
                }
            }
        }
    }
    return dp[n][m];
}

