std::string decimalToBinary(double num, int k_prec) {
    std::string binary = "";
    // Extract integral part
    int Integral = static_cast<int>(num);
    // Extract fractional part
    double fractional = num - Integral;
    // Convert integral part to binary
    while (Integral > 0) {
        int rem = Integral % 2;
        binary += std::to_string(rem);
        Integral /= 2;
    }
    // Reverse the integral part binary representation
    std::reverse(binary.begin(), binary.end());
    // Add the decimal point
    binary += '.';
    // Convert fractional part to binary
    while (k_prec > 0) {
        fractional *= 2;
        int fract_bit = static_cast<int>(fractional);
        if (fract_bit == 1) {
            fractional -= fract_bit;
            binary += '1';
        } else {
            binary += '0';
        }
        k_prec--;
    }
    return binary;
}

