int possibleStrings(int n, int r, int b, int g) {
    // Initialize the factorial array.
    std::vector<int> fact(n + 1, 0);
    fact[0] = 1;
    // Compute factorial values.
    for (int i = 1; i <= n; ++i) {
        fact[i] = fact[i - 1] + i;
    }
    int left = n - (r + g + b);
    int sum = 0;
    // Iterate through all possible combinations.
    for (int i = 0; i <= left; ++i) {
        for (int j = 0; j <= left - i; ++j) {
            int k = left - (i + j);
            sum += static_cast<int>(fact[n] / (fact[i + r] + fact[j + b] + fact[k + g]));
        }
    }
    return sum;
}

