int eggDrop(int n, int k) {
    vector<vector<int>> eggFloor(n + 1, vector<int>(k + 1, 0));
    // Base cases
    for (int i = 1; i <= n; i++) {
        eggFloor[i][1] = 1; // One trial for one floor
        eggFloor[i][0] = 0; // Zero trials for zero floors
    }
    for (int j = 1; j <= k; j++) {
        eggFloor[1][j] = j; // j trials for one egg and j floors
    }
    // Fill the rest of the table
    for (int i = 2; i <= n; i++) {
        for (int j = 2; j <= k; j++) {
            eggFloor[i][j] = INT_MAX;
            for (int x = 1; x <= j; x++) {
                int res = 1 + max(eggFloor[i - 1][x - 1], eggFloor[i][j - x]);
                if (res < eggFloor[i][j]) {
                    eggFloor[i][j] = res;
                }
            }
        }
    }
