int minPalPartition(string str) {
    int n = str.length();
    vector<vector<int>> C(n, vector<int>(n, 0));
    vector<vector<bool>> P(n, vector<bool>(n, false));
    int j, k, L;
    // Initialize for single character substrings
    for (int i = 0; i < n; i++) {
        P[i][i] = true;
        C[i][i] = 0;
    }
    // Process substrings of length 2 to n
    for (L = 2; L <= n; L++) {
        for (int i = 0; i < n - L + 1; i++) {
            j = i + L - 1; // End index of the current substring
            if (L == 2) {
                P[i][j] = (str[i] == str[j]);
            } else {
                P[i][j] = (str[i] == str[j]) && P[i + 1][j - 1];
            }
            if (P[i][j]) {
                C[i][j] = 0;
            } else {
                C[i][j] = INT_MAX;
                for (k = i; k < j; k++) {
                    C[i][j] = min(C[i][j], C[i][k] + C[k + 1][j] + 1);
                }
            }
        }
    }
    return C[0][n - 1];
}

