    vector<vector<int>> F(n, vector<int>(n, 0));
    vector<vector<int>> T(n, vector<int>(n, 0));
    for (int i = 0; i < n; i++) {
        if (symb[i] == 'F') {
            F[i][i] = 1;
        } else {
            F[i][i] = 0;
        }
        if (symb[i] == 'T') {
            T[i][i] = 1;
        } else {
