int maxPrimeFactors(int n) {
    int maxPrime = -1;
    // Divide n by 2 as long as it is divisible
    while (n % 2 == 0) {
        maxPrime = 2;
        n >>= 1; // equivalent to n = n / 2
    }
    // Check for odd factors from 3 to sqrt(n)
    for (int i = 3; i <= std::sqrt(n); i += 2) {
        while (n % i == 0) {
            maxPrime = i;
            n = n / i;
        }
    }
    // If n is a prime number greater than 2
    if (n > 2) {
        maxPrime = n;
    }
    return maxPrime;
}

