int sumofoddFactors(int n) {
    int res = 1;
    // Remove all even factors of n
    while (n % 2 == 0) {
        n /= 2;
    }
    // Process odd factors from 3 up to sqrt(n)
    for (int i = 3; i <= sqrt(n); i += 2) {
        int count = 0;
        int curr_sum = 1;
        int curr_term = 1;
        while (n % i == 0) {
            count++;
            n /= i;
            curr_term *= i;
            curr_sum += curr_term;
        }
        res *= curr_sum;
    }
    // If n is still greater than or equal to 2, it's a prime factor
    if (n >= 2) {
        res *= (1 + n);
    }
    return res;
}

