int pairsInSortedRotated(int arr[], int n, int x) {
    // Find the pivot element
    int i;
    for (i = 0; i < n - 1; i++) {
        if (arr[i] > arr[i + 1]) {
            break;
        }
    }
    // l is the index of the smallest element
    int l = (i + 1) % n;
    // r is the index of the largest element
    int r = i;
    int cnt = 0;
    // Loop to find pairs with sum x
    while (l != r) {
        if (arr[l] + arr[r] == x) {
            cnt++;
            // If l and r meet, break the loop
            if (l == (r - 1 + n) % n) {
                return cnt;
            }
            l = (l + 1) % n;
            r = (r - 1 + n) % n;
        } else if (arr[l] + arr[r] < x) {
            l = (l + 1) % n;
        } else {
            r = (n + r - 1) % n;
        }
    }
    return cnt;
}
