bool prevPermutation(std::string& str) {
    int n = str.length() - 1;
    int i = n;
    // Find the first character that is smaller than the one next to it
    while (i > 0 && str[i - 1] <= str[i]) {
        i--;
    }
    // If i <= 0, it means the string is already the lowest permutation
    if (i <= 0) {
        return false;
    }
    int j = i - 1;
    // Find the largest character to the right of i - 1 that is smaller than str[i - 1]
    while (j + 1 <= n && str[j + 1] <= str[i - 1]) {
        j++;
    }
    // Swap characters at i - 1 and j
    std::swap(str[i - 1], str[j]);
    // Reverse the substring to the right of i - 1
    std::reverse(str.begin() + i, str.end());
    return true;
}

