string maximumPalinUsingKChanges(string str, int k) {
    string palin = str;
    int l = 0, r = str.length() - 1;
    // First pass: Make the string a palindrome
    while (l <= r) {
        if (str[l] != str[r]) {
            palin[l] = palin[r] = max(str[l], str[r]);
            k--;
        }
        l++;
        r--;
    }
    // If k is negative, it's not possible to make it a palindrome
    if (k < 0) {
        return "Not possible";
    }
    l = 0;
    r = str.length() - 1;
    // Second pass: Maximize the palindrome
    while (l <= r) {
        if (l == r) {
            // If there's a middle character and k > 0, set it to '9'
            if (k > 0) {
                palin[l] = '9';
            }
        }
        if (palin[l] < '9') {
            // If both characters were unchanged and we have at least 2 changes left
            if (k >= 2 && palin[l] == str[l] && palin[r] == str[r]) {
                k -= 2;
                palin[l] = palin[r] = '9';
            }
            // If either character was changed earlier and we have at least 1 change left
            else if (k >= 1 && (palin[l] != str[l] || palin[r] != str[r])) {
                k -= 1;
                palin[l] = palin[r] = '9';
            }
        }
        l++;
        r--;
    }
    return palin;
}

