int smallestSubWithSum(vector<int>& arr, int n, int x) {
    int curr_sum = 0;
    int min_len = n + 1;
    int start = 0, end = 0;
    while (end < n) {
        // Expand the window to include elements until curr_sum > x
        while (curr_sum <= x && end < n) {
            if (curr_sum <= 0 && x > 0) {
                start = end;
                curr_sum = 0;
            }
            curr_sum += arr[end];
            end++;
        }
        // Reduce the window size while curr_sum > x
        while (curr_sum > x && start < n) {
            if (end - start < min_len) {
                min_len = end - start;
            }
            curr_sum -= arr[start];
            start++;
        }
    }
    return min_len;
}

