int find_maximum(vector<int>& a, int n, int k) {
    unordered_map<int, int> b;
    for (int i = 0; i < n; i++) {
        int x = a[i];
        int d = min(1 + i, n - i);
        if (b.find(x) == b.end()) {
            b[x] = d;
        } else {
            b[x] = min(d, b[x]);
        }
    }
    int ans = INT_MAX;
    for (int i = 0; i < n; i++) {
        int x = a[i];
        if (x != (k - x) && b.find(k - x) != b.end()) {
