    }
    string str = "";
    int n1 = str1.length();
    int n2 = str2.length();
    // Reverse the strings
    reverse(str1.begin(), str1.end());
    reverse(str2.begin(), str2.end());
    int carry = 0;
    // Sum the digits of the shorter string
    for (int i = 0; i < n1; i++) {
        int sum = ((str1[i] - '0') + ((str2[i] - '0') + carry));
        if (sum < 0) {
            str += (char)(sum % -10 + '0');
        } else {
            str += (char)(sum % 10 + '0');
        }
        carry = sum / 10;
    }
    // Sum the remaining digits of the longer string
    for (int i = n1; i < n2; i++) {
        int sum = ((str2[i] - '0') + carry);
        if (sum < 0) {
            str += (char)(sum % -10 + '0');
        } else {
            str += (char)(sum % 10 + '0');
        }
        carry = sum / 10;
    }
    // Add any remaining carry
    if (carry) {
        str += (char)(carry + '0');
    }
    // Reverse the result
    reverse(str.begin(), str.end());
    return str;
}
