unsigned int swapBits(unsigned int x, unsigned int p1, unsigned int p2, unsigned int n) {
    // Extract the sets of bits at positions p1 and p2
    unsigned int set1 = (x >> p1) & ((1 << n) - 1);
    unsigned int set2 = (x >> p2) & ((1 << n) - 1);
    // XOR the two sets of bits
    unsigned int xor = (set1 ^ set2);
    // Shift the XOR result to the positions p1 and p2
    xor = (xor << p1) | (xor << p2);
    // Apply the XOR operation to swap the bits in the original number
    unsigned int result = x ^ xor;
    return result;
}

