bool isMultipleOf3(int n) {
    int odd_count = 0;
    int even_count = 0;
    if (n < 0) {
        n = -n;
    }
    if (n == 0) {
        return true;
    }
    if (n == 1) {
        return false;
    }
    while (n) {
        if (n & 1) {
            odd_count++;
        }
        if (n & 2) {
            even_count++;
        }
        n = n >> 2;
    }
    return isMultipleOf3(abs(odd_count - even_count));
}

